import React, { useState, useEffect, useRef } from 'react';
import './Css/Community.css'; // FIXED IMPORT PATH

const ChatWindow = ({ currentUser, targetUser, onClose }) => {
  const [messages, setMessages] = useState([]);
  const [newMessage, setNewMessage] = useState('');
  const messagesEndRef = useRef(null);

  // Fetch conversation history
  const fetchMessages = async () => {
    try {
      const res = await fetch(`http://localhost:8000/api/community/messages?user1=${currentUser}&user2=${targetUser}`);
      const data = await res.json();
      if (data.status === 'success') {
        setMessages(data.messages);
      }
    } catch (err) { console.error("Failed to fetch messages", err); }
  };

  // Poll for new messages every 3 seconds (Simple Real-time)
  useEffect(() => {
    fetchMessages();
    const interval = setInterval(() => { fetchMessages(); }, 3000);
    return () => clearInterval(interval);
  }, [currentUser, targetUser]);

  // Auto-scroll to the newest message
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  const handleSend = async () => {
    if (!newMessage.trim()) return;
    try {
      await fetch('http://localhost:8000/api/community/messages', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ sender: currentUser, receiver: targetUser, content: newMessage })
      });
      setNewMessage('');
      fetchMessages(); // instantly refresh
    } catch (err) { alert("Failed to send"); }
  };

  const handleKeyPress = (e) => {
    if (e.key === 'Enter') handleSend();
  };

  return (
    <div className="active-chat-container">
      {/* Chat Header */}
      <div className="active-chat-header">
        <button className="back-btn" onClick={onClose}>←</button>
        <div className="chat-avatar" style={{width: '30px', height: '30px'}}>{targetUser.charAt(0).toUpperCase()}</div>
        <div className="chat-target-name">{targetUser}</div>
      </div>

      {/* Message Bubbles */}
      <div className="chat-messages-area">
        {messages.length === 0 ? (
          <div className="empty-chat-msg">Say hi to {targetUser}!</div>
        ) : (
          messages.map((msg) => {
            const isMe = msg.sender_username === currentUser;
            return (
              <div key={msg.id} className={`message-wrapper ${isMe ? 'message-mine' : 'message-theirs'}`}>
                <div className="message-bubble">{msg.content}</div>
              </div>
            );
          })
        )}
        <div ref={messagesEndRef} /> {/* Invisible div to scroll down to */}
      </div>

      {/* Input Area */}
      <div className="chat-input-area">
        <input 
          type="text" 
          placeholder={`Message ${targetUser}...`} 
          value={newMessage}
          onChange={(e) => setNewMessage(e.target.value)}
          onKeyDown={handleKeyPress}
        />
        <button onClick={handleSend}>Send</button>
      </div>
    </div>
  );
};

export default ChatWindow;
